 workspace.CurrentCamera local RootPos, OnScreen = Camera:WorldToViewportPoint(RootPart.Position) local HeadPos = Camera:WorldToViewportPoint(Head.Position + Vector3.new(0, 0.5, 0)) local LegPos = Camera:WorldToViewportPoint(RootPart.Position - Vector3.new(0, 3, 0)) if OnScreen then if Settings.ESPBoxes then Box.Visible = true Box.Size = Vector2.new(2000 / RootPos.Z, HeadPos.Y - LegPos.Y) Box.Position = Vector2.new(RootPos.X - Box.Size.X / 2, RootPos.Y - Box.Size.Y / 2) Box.Color = Settings.ESPColor Box.Thickness = 1 Box.Filled = false else Box.Visible = false end if Settings.ESPTracer then Tracer.Visible = true Tracer.From = Vector2.new(Camera.ViewportSize.X / 2, 0) Tracer.To = Vector2.new(RootPos.X, RootPos.Y - (Box.Size.Y / 2)) Tracer.Color = Settings.ESPColor else Tracer.Visible = false end if Settings.ESPHealth then HealthBar.Visible = true HealthBar.Color = Color3.fromRGB(0, 255, 0) local HealthPercentage = player.Character.Humanoid.Health / player.Character.Humanoid.MaxHealth local FullHeight = HeadPos.Y - LegPos.Y HealthBar.From = Vector2.new(RootPos.X - (Box.Size.X / 2) - 5, LegPos.Y) HealthBar.To = Vector2.new(RootPos.X - (Box.Size.X / 2) - 5, LegPos.Y + (FullHeight * HealthPercentage)) else HealthBar.Visible = false end if Settings.ESPItems then local Equipment = "а№„аёЎа№ҲаёЎаёөа№„аёӯа№Җаё—аёЎ" local Tool = player.Character:FindFirstChildOfClass("Tool") if Tool then Equipment = "аё–аё·аёӯаёӯаёўаё№а№Ҳ: " .. Tool.Name else local BackTool = player.Backpack:FindFirstChildOfClass("Tool") if BackTool then Equipment = "а№ғаёҷаёҒаёЈаё°а№Җаёӣа№ӢаёІ: " .. BackTool.Name end end ItemText.Visible = true ItemText.Text = Equipment ItemText.Size = 16 ItemText.Center = true ItemText.Outline = true ItemText.Color = Color3.fromRGB(255, 255, 0) ItemText.Position = Vector2.new(RootPos.X, LegPos.Y + 10) else ItemText.Visible = false end else Box.Visible = false; Tracer.Visible = false; HealthBar.Visible = false; ItemText.Visible = false end else Box.Visible = false; Tracer.Visible = false; HealthBar.Visible = false; ItemText.Visible = false end end) end for _, p in pairs(game.Players:GetPlayers()) do CreateESP(p) end game.Players.PlayerAdded:Connect(CreateESP) game:GetService("RunService").RenderStepped:Connect(function() FOVCircle.Position = Vector2.new(workspace.CurrentCamera.ViewportSize.X / 2, workspace.CurrentCamera.ViewportSize.Y / 2) FOVCircle.Radius = Settings.FOVRadius FOVCircle.Visible = Settings.FOVVisible FOVCircle.Color = Settings.FOVColor if Settings.AimbotEnabled then local Target = GetClosestPlayer() if Target then workspace.CurrentCamera.CFrame = CFrame.new(workspace.CurrentCamera.CFrame.Position, Target.Position) end end end) local MainTab = Window:CreateTab("аёЈаё°аёҡаёҡаёҘа№Үаёӯаё„аё«аёұаё§", 4483362458) MainTab:CreateToggle({ Name = "а№Җаёӣаёҙаё”а№ғаёҠа№үаёҮаёІаёҷ аёҘа№Үаёӯаё„аё«аёұаё§", CurrentValue = false, Callback = function(Value) Settings.AimbotEnabled = Value end, }) MainTab:CreateSlider({ Name = "аёӣаёЈаёұаёҡаё„аё§аёІаёЎа№ғаё«аёҚа№Ҳ FOV", Range = {50, 600}, Increment = 10, CurrentValue = 100, Callback = function(Value) Settings.FOVRadius = Value end, }) MainTab:CreateToggle({ Name = "а№ҒаёӘаё”аёҮаё§аёҮаёҒаёҘаёЎ FOV", CurrentValue = true, Callback = function(Value) Settings.FOVVisible = Value end, }) MainTab:CreateColorPicker({ Name = "аёӘаёөаё§аёҮаёҒаёҘаёЎ FOV", Color = Settings.FOVColor, Callback = function(Value) Settings.FOVColor = Value end }) local ESPTab = Window:CreateTab("аёЈаё°аёҡаёҡаёЎаёӯаёҮаё—аё°аёҘаёё", 4483362458) ESPTab:CreateToggle({ Name = "а№Җаёӣаёҙаё”а№ғаёҠа№үаёҮаёІаёҷаёЎаёӯаёҮаё—аё°аёҘаёё", CurrentValue = false, Callback = function(Value) Settings.ESPEnabled = Value end, }) ESPTab:CreateToggle({ Name = "а№ҒаёӘаё”аёҮаёҒаёЈаёӯаёҡа№ӮаёӣаёЈа№ҲаёҮа№ҒаёӘаёҮ", CurrentValue = true, Callback = function(Value) Settings.ESPBoxes = Value end, }) ESPTab:CreateToggle({ Name = "а№ҒаёӘаё”аёҮа№ҖаёӘа№үаёҷаёҠаёөа№үаёҲаёІаёҒаёӮаёӯаёҡаёҡаёҷ", CurrentValue = true, Callback = function(Value) Settings.ESPTracer =